import{_ as n,H as a,f as l,i as p}from"./chunks/framework.BHvCMIhP.js";const h=JSON.parse('{"title":"架构演进史","description":"","frontmatter":{},"headers":[],"relativePath":"systemDesign/03-架构演进史.md","filePath":"systemDesign/03-架构演进史.md","lastUpdated":1778496697000}'),e={name:"systemDesign/03-架构演进史.md"};function t(i,s,o,r,c,d){return a(),l("div",null,[...s[0]||(s[0]=[p(`<h1 id="架构演进史" tabindex="-1">架构演进史 <a class="header-anchor" href="#架构演进史" aria-label="Permalink to &quot;架构演进史&quot;">​</a></h1><p>每一代架构都是<strong>被前一代的瓶颈逼出来的</strong>,不是工程师为了用新技术。理解这条演进链,你会发现「微服务」「Service Mesh」「Cell 架构」不是潮流名词,是<strong>真实痛点的解决方案</strong>。新手最爱犯的错是「我们用单体就行」或者反过来「上来就微服务」——其实在哪一代,<strong>只跟你的团队规模 + 流量规模有关</strong>。这一篇按时间线走一遍,看清每一步「为什么不得不升级」。</p><blockquote><p>一句话先记住:<strong>架构演进的驱动力永远是两个东西——流量增长压垮了上一代,组织变大撕裂了上一代</strong>。技术只是表象,<strong>「哪一代架构合适你」=「你团队多少人 + 你 QPS 多少」交叉决定</strong>——20 人团队上 200 个微服务就是自杀,500 人公司还在跑单体也是自杀。</p></blockquote><hr><h2 id="一、v0-单机一切-lamp-单文件" tabindex="-1">一、V0:单机一切(LAMP / 单文件) <a class="header-anchor" href="#一、v0-单机一切-lamp-单文件" aria-label="Permalink to &quot;一、V0:单机一切(LAMP / 单文件)&quot;">​</a></h2><p>时间:2000 - 2010 早期</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────┐</span></span>
<span class="line"><span>│  一台物理机                      │</span></span>
<span class="line"><span>│  Apache + PHP + MySQL + 静态文件 │</span></span>
<span class="line"><span>└────────────────────────────────┘</span></span></code></pre></div><p><strong>特征</strong>:</p><ul><li>代码、DB、文件、缓存全在一台机器</li><li>部署 = ssh 上去 <code>git pull</code></li><li>备份 = <code>mysqldump</code> + scp</li></ul><p><strong>适用规模</strong>:DAU &lt; 1 万,内部工具、个人博客、小公司官网。</p><p><strong>瓶颈来源</strong>:</p><ul><li>单机 CPU / 内存上限</li><li>单机宕机 = 服务整体挂掉(0 高可用)</li><li>部署时短暂不可用</li><li>一个慢 SQL 拖死整个机器</li></ul><blockquote><p>别小看 V0,<strong>今天 90% 的 SaaS 创业项目第一年都该是 V0</strong>——别上来就 K8s,3 个用户根本不需要。<strong>Stack Overflow 直到 1000 万 DAU 都还基本是 V0 的进化版</strong>(只 9 台 Web 服务器),活生生的反例。</p></blockquote><hr><h2 id="二、v1-应用与数据分离" tabindex="-1">二、V1:应用与数据分离 <a class="header-anchor" href="#二、v1-应用与数据分离" aria-label="Permalink to &quot;二、V1:应用与数据分离&quot;">​</a></h2><p>时间:2005 - 2015</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────┐         ┌──────────┐</span></span>
<span class="line"><span>│  Web 1   │ ──────▶ │  MySQL   │</span></span>
<span class="line"><span>└──────────┘         └──────────┘</span></span></code></pre></div><p><strong>改变</strong>:把 DB 单独拆出来,Web 服务器和数据库各占一台。</p><p><strong>为什么</strong>:</p><ul><li>DB 和应用对硬件要求不同——DB 吃内存 / 磁盘,Web 吃 CPU</li><li>DB 重启 / 优化不影响 Web 部署</li></ul><p><strong>新瓶颈</strong>:</p><ul><li>Web 单点(挂了全挂)</li><li>DB 单点(挂了全挂)</li><li>静态资源占用 Web 带宽</li></ul><hr><h2 id="三、v2-多-web-负载均衡-静态分离" tabindex="-1">三、V2:多 Web + 负载均衡 + 静态分离 <a class="header-anchor" href="#三、v2-多-web-负载均衡-静态分离" aria-label="Permalink to &quot;三、V2:多 Web + 负载均衡 + 静态分离&quot;">​</a></h2><p>时间:2010 - 2020,绝大部分中型项目的当前形态</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                     ┌──────────┐</span></span>
<span class="line"><span>                     │  Web 1   │ ────┐</span></span>
<span class="line"><span>┌──────────┐ ──▶ ┌──┐  Web 2   │ ────┤    ┌──────────┐</span></span>
<span class="line"><span>│  Client  │     │LB│  Web 3   │ ────┼──▶ │  MySQL   │</span></span>
<span class="line"><span>└──────────┘ ──▶ └──┘  Web 4   │ ────┘    └──────────┘</span></span>
<span class="line"><span>                     └──────────┘</span></span>
<span class="line"><span>                          ↓</span></span>
<span class="line"><span>                     ┌──────────┐</span></span>
<span class="line"><span>                     │   CDN    │  (静态资源)</span></span>
<span class="line"><span>                     └──────────┘</span></span></code></pre></div><p><strong>改变</strong>:</p><ul><li>多台 Web,前面挂 LB(Nginx / AWS ALB)</li><li>静态资源(图片、JS / CSS)走 CDN</li><li>这一代起,Web 必须做成<strong>无状态</strong>(Session 进 Redis 或 Cookie)</li></ul><p><strong>为什么</strong>:</p><ul><li>Web 任何一台挂了 LB 自动剔除——<strong>真正的高可用从这一代开始</strong></li><li>加机器就能扛更多流量(水平扩展)</li><li>静态资源不再吃 Web 带宽,延迟也低</li></ul><p><strong>新瓶颈</strong>:</p><ul><li>DB 仍是单点</li><li>DB 撑不住读 QPS</li></ul><blockquote><p><strong>大多数公司在 V2 卡很久</strong>——只要 DB 没爆,V2 + 缓存就能撑到 DAU 100 万。<strong>别为了&quot;显得现代&quot;提前升级</strong>。</p></blockquote><hr><h2 id="四、v3-db-主从复制-读写分离-缓存" tabindex="-1">四、V3:DB 主从复制 + 读写分离 + 缓存 <a class="header-anchor" href="#四、v3-db-主从复制-读写分离-缓存" aria-label="Permalink to &quot;四、V3:DB 主从复制 + 读写分离 + 缓存&quot;">​</a></h2><p>时间:2010 至今,中大型系统标配</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                     ┌──────────┐</span></span>
<span class="line"><span>                     │  Web ×N  │</span></span>
<span class="line"><span>                     └──────────┘</span></span>
<span class="line"><span>                       ↓ 读  ↑ 写</span></span>
<span class="line"><span>              ┌────────┴───────┐</span></span>
<span class="line"><span>         ┌────┴────┐       ┌──────────┐</span></span>
<span class="line"><span>         │  Redis  │ ◀───  │ MySQL 主 │</span></span>
<span class="line"><span>         └─────────┘       └────┬─────┘</span></span>
<span class="line"><span>                                ↓ 复制</span></span>
<span class="line"><span>                     ┌──────────┴──────────┐</span></span>
<span class="line"><span>                ┌────┴────┐         ┌──────┴───┐</span></span>
<span class="line"><span>                │MySQL 从1│   ...   │MySQL 从n │</span></span>
<span class="line"><span>                └─────────┘         └──────────┘</span></span></code></pre></div><p><strong>改变</strong>:</p><ul><li>MySQL 一主多从,读分散到从库,写只在主库</li><li>Redis 缓存热点数据(用户信息、配置、热门列表)</li><li>应用层负责「读哪个 / 写哪个」的路由</li></ul><p><strong>为什么</strong>:</p><ul><li>读 QPS 单机 5-10 倍提升(从库越多扩越多)</li><li>缓存命中率 80%+,DB 实际负载降一个量级</li></ul><p><strong>新瓶颈</strong>:</p><ul><li>主从复制延迟(写入主库到从库可见有 100ms ~ 几秒)</li><li>主库写入仍是瓶颈</li><li>单库数据量到几亿行后查询变慢</li></ul><blockquote><p>这一代关键学问是<strong>主从延迟</strong>——刚下单的用户立刻刷新,可能查不到自己的订单(查到了从库,主库刚写的还没复制过来)。<strong>关键写入后立即读必须强制走主库</strong>(<code>SET TRANSACTION_READ_WRITE</code> 或应用层标记)。</p></blockquote><hr><h2 id="五、v4-垂直拆分-按业务模块拆库-拆服务" tabindex="-1">五、V4:垂直拆分(按业务模块拆库 + 拆服务) <a class="header-anchor" href="#五、v4-垂直拆分-按业务模块拆库-拆服务" aria-label="Permalink to &quot;五、V4:垂直拆分(按业务模块拆库 + 拆服务)&quot;">​</a></h2><p>时间:2012 至今</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────┐  ┌────────────┐  ┌────────────┐  ┌────────────┐</span></span>
<span class="line"><span>│ User 服务   │  │ Order 服务  │  │Product 服务│  │Comment 服务│</span></span>
<span class="line"><span>└─────┬──────┘  └─────┬──────┘  └─────┬──────┘  └─────┬──────┘</span></span>
<span class="line"><span>      ↓               ↓               ↓               ↓</span></span>
<span class="line"><span>┌─────┴──────┐ ┌─────┴──────┐ ┌─────┴──────┐ ┌─────┴──────┐</span></span>
<span class="line"><span>│  User DB   │ │  Order DB  │ │ Product DB │ │ Comment DB │</span></span>
<span class="line"><span>└────────────┘ └────────────┘ └────────────┘ └────────────┘</span></span></code></pre></div><p><strong>改变</strong>:</p><ul><li>按业务模块切应用(User / Order / Product 各自一套服务)</li><li>每个服务有自己的 DB(<strong>库不再共享</strong>)</li><li>服务间通过 HTTP / RPC 调用</li></ul><p><strong>为什么</strong>:</p><ul><li>单库数据量 / 写入量到上限,垂直拆是最自然的</li><li>团队人多了(50+),不同模块代码冲突严重</li><li>不同模块发布节奏不同(Order 一天 10 次,User 一周 1 次),单体变累赘</li></ul><p><strong>新瓶颈</strong>:</p><ul><li><strong>单业务</strong>仍可能太大(Order 表自己就 100 亿行)</li><li>跨服务事务(下单 = User 扣余额 + Order 写表 + Product 减库存)</li><li>分布式调用复杂度上升</li></ul><blockquote><p><strong>垂直拆是组织规模的产物</strong>,不是流量。<strong>就算流量小,只要团队 &gt; 50 人,该拆还是要拆</strong>——不然代码变成谁也不敢动的泥球。</p></blockquote><hr><h2 id="六、v5-水平拆分-分库分表" tabindex="-1">六、V5:水平拆分(分库分表) <a class="header-anchor" href="#六、v5-水平拆分-分库分表" aria-label="Permalink to &quot;六、V5:水平拆分(分库分表)&quot;">​</a></h2><p>时间:2013 至今,大流量系统标配</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                     ┌────────────┐</span></span>
<span class="line"><span>                     │ Order 服务  │</span></span>
<span class="line"><span>                     └─────┬──────┘</span></span>
<span class="line"><span>                           │ 路由(按 user_id 哈希)</span></span>
<span class="line"><span>              ┌────────────┼────────────────────┐</span></span>
<span class="line"><span>              ↓            ↓                    ↓</span></span>
<span class="line"><span>       ┌─────────────┐ ┌─────────────┐    ┌─────────────┐</span></span>
<span class="line"><span>       │ Order DB 0  │ │ Order DB 1  │... │Order DB 1023│</span></span>
<span class="line"><span>       │  shard_0~7  │ │  shard_8~15 │    │             │</span></span>
<span class="line"><span>       └─────────────┘ └─────────────┘    └─────────────┘</span></span></code></pre></div><p><strong>改变</strong>:</p><ul><li>同一业务的同一张表,按某个键(user_id)切成 N 份(shard)</li><li>应用通过分片路由器找到对应分片</li><li>物理上分散到多台 MySQL</li></ul><p><strong>为什么</strong>:</p><ul><li>单业务也撑不住单机:Order 表 100 亿行,单库慢</li><li>写入 QPS 也分散到 N 个主库</li></ul><p><strong>新瓶颈</strong>:</p><ul><li>分片键选错就是地狱(非分片键查询要扫全部分片)</li><li>跨分片 join 基本不可能,要在应用层做</li><li>全局唯一 ID 需要分布式发号器(雪花 / TiDB 风格)</li><li>数据迁移、扩容极其麻烦(从 8 分片扩到 16 分片)</li></ul><blockquote><p><strong>分库分表是&quot;上一步&quot;——一旦做了就不可逆</strong>。千万别因为&quot;听说要分库&quot;就提前分,<strong>先用所有能扛的招(读写分离、缓存、归档老数据)再分</strong>。一旦分了,后面三年都在还分库的债。</p></blockquote><hr><h2 id="七、v6-微服务-服务治理-注册中心-网关" tabindex="-1">七、V6:微服务 + 服务治理(注册中心 + 网关) <a class="header-anchor" href="#七、v6-微服务-服务治理-注册中心-网关" aria-label="Permalink to &quot;七、V6:微服务 + 服务治理(注册中心 + 网关)&quot;">​</a></h2><p>时间:2014 至今</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       ┌─────────────┐    ┌──────────────┐</span></span>
<span class="line"><span>       │  API Gateway│    │Service Registry│ (Nacos / Consul)</span></span>
<span class="line"><span>       └──────┬──────┘    └──────────────┘</span></span>
<span class="line"><span>              │                 ↑↓ 注册 / 发现</span></span>
<span class="line"><span>   ┌──────────┼──────────┐</span></span>
<span class="line"><span>   ↓          ↓          ↓</span></span>
<span class="line"><span>┌────┐  ┌─────────┐  ┌─────────┐</span></span>
<span class="line"><span>│User│  │ Order   │  │Product  │  ......(几十~几百个服务)</span></span>
<span class="line"><span>└────┘  └─────────┘  └─────────┘</span></span>
<span class="line"><span>   ↓         ↓         ↓</span></span>
<span class="line"><span>[各自的 DB / 缓存 / MQ]</span></span></code></pre></div><p><strong>改变</strong>:</p><ul><li>服务粒度更细(从「Order 服务」拆成「OrderCreate / OrderQuery / OrderAfterSale 」)</li><li>引入服务注册中心(谁活着、IP 多少自动同步)</li><li>引入 API 网关(统一鉴权、限流、路由、日志)</li><li>配置中心、链路追踪、监控等成为基础设施</li></ul><p><strong>为什么</strong>:</p><ul><li>团队 200+ 人,微服务支持每个小队独立发版</li><li>业务复杂度爆炸,需要<strong>清晰的服务边界 + 标准化治理</strong></li></ul><p><strong>新瓶颈</strong>:</p><ul><li>服务依赖图变成蜘蛛网(几百个服务调来调去)</li><li>排查链路问题:一个请求过 20 个服务,谁慢?</li><li>部署复杂度炸裂(每个服务自己一套 CI / CD)</li><li><strong>基础设施投入比业务代码还多</strong></li></ul><blockquote><p><strong>微服务的代价被严重低估</strong>——一个 50 人团队上微服务,会发现 80% 的精力都在治理,而不是写业务。<strong>没到 200 人 + 多业务线,别上微服务</strong>。</p></blockquote><hr><h2 id="八、v7-service-mesh-容器编排" tabindex="-1">八、V7:Service Mesh + 容器编排 <a class="header-anchor" href="#八、v7-service-mesh-容器编排" aria-label="Permalink to &quot;八、V7:Service Mesh + 容器编排&quot;">​</a></h2><p>时间:2018 至今</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                ┌─────────────┐</span></span>
<span class="line"><span>                │  K8s + Istio│</span></span>
<span class="line"><span>                └─────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每个 Pod = 业务容器 + Sidecar 代理(Envoy)</span></span>
<span class="line"><span>所有 RPC 走 Sidecar:</span></span>
<span class="line"><span>  - 自动 mTLS</span></span>
<span class="line"><span>  - 自动重试 / 熔断 / 限流</span></span>
<span class="line"><span>  - 自动链路追踪</span></span>
<span class="line"><span>  - 自动金丝雀发布</span></span>
<span class="line"><span></span></span>
<span class="line"><span>业务代码不感知,治理逻辑在 Sidecar</span></span></code></pre></div><p><strong>改变</strong>:</p><ul><li>治理逻辑(熔断、限流、加密、重试)从业务代码下沉到 Sidecar</li><li>容器编排(K8s)统一调度 / 滚动 / 弹性</li><li>多语言混合架构成为可能(Go + Java + Python 都能用同一套治理)</li></ul><p><strong>为什么</strong>:</p><ul><li>V6 的治理 SDK(Spring Cloud / Dubbo)绑死语言,多语言团队痛</li><li>治理升级要每个服务改代码,慢</li><li>容器化让基础设施可编程</li></ul><p><strong>新瓶颈</strong>:</p><ul><li>Sidecar 增加 1ms+ 延迟,每个服务多占 100MB 内存</li><li>排查问题更难(业务请求要穿过两层代理)</li><li>学 K8s + Istio 的成本巨大,需要专门 SRE 团队</li></ul><blockquote><p><strong>Service Mesh 不是「更先进」,是「更复杂」</strong>。如果你不是大厂或多语言团队,<strong>继续用 V6 的 Spring Cloud / Dubbo 完全够</strong>。<strong>Mesh 是给 1000+ 服务的公司用的,不是给创业公司用的</strong>。</p></blockquote><hr><h2 id="九、v8-cell-单元化-异地多活" tabindex="-1">九、V8:Cell / 单元化 / 异地多活 <a class="header-anchor" href="#九、v8-cell-单元化-异地多活" aria-label="Permalink to &quot;九、V8:Cell / 单元化 / 异地多活&quot;">​</a></h2><p>时间:2017 至今,只在头部公司</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────── 北京机房 (Cell-A) ───────────────┐</span></span>
<span class="line"><span>│ 完整一套服务: User / Order / DB / Cache / MQ    │</span></span>
<span class="line"><span>│  服务 0~100M 用户                              │</span></span>
<span class="line"><span>└────────────────────────────────────────────────┘</span></span>
<span class="line"><span>              ↕ 跨机房同步(数据)</span></span>
<span class="line"><span>┌─────────────── 上海机房 (Cell-B) ───────────────┐</span></span>
<span class="line"><span>│ 完整一套服务                                     │</span></span>
<span class="line"><span>│  服务 100M~200M 用户                           │</span></span>
<span class="line"><span>└────────────────────────────────────────────────┘</span></span>
<span class="line"><span>              ↕</span></span>
<span class="line"><span>┌─────────────── 深圳机房 (Cell-C) ───────────────┐</span></span>
<span class="line"><span>│ ...                                            │</span></span>
<span class="line"><span>└────────────────────────────────────────────────┘</span></span></code></pre></div><p><strong>改变</strong>:</p><ul><li>每个 Cell 是<strong>自包含的微型系统</strong>(从入口到 DB 都全)</li><li>用户按 ID 路由到固定 Cell(就近 + 容灾)</li><li>Cell 内部低延迟,跨 Cell 只走异步同步</li><li>单 Cell 挂了影响 1/N 用户,且能快速切到其他 Cell</li></ul><p><strong>为什么</strong>:</p><ul><li>单机房的物理上限到了(电力 / 散热 / 带宽)</li><li>政策 / 合规要求数据本地化</li><li>灾难恢复:一个机房挂了不能全网瘫</li></ul><p><strong>新瓶颈</strong>:</p><ul><li>跨 Cell 数据一致性极难(下单时商品库存在另一个 Cell)</li><li>部署、变更需要全 Cell 同步</li><li>成本数倍上升</li></ul><blockquote><p>阿里 LDC、字节 SCS、Google Spanner 都是这一代的产物。<strong>这是 1 亿 DAU 以上才会碰到的世界</strong>——你不在那种公司就别学,学了也没场景用。</p></blockquote><hr><h2 id="十、对照表-每一代「拐点」是什么" tabindex="-1">十、对照表:每一代「拐点」是什么 <a class="header-anchor" href="#十、对照表-每一代「拐点」是什么" aria-label="Permalink to &quot;十、对照表:每一代「拐点」是什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>代</th><th>升级触发条件</th><th>抛弃了什么</th></tr></thead><tbody><tr><td>V0 → V1</td><td>DB 和 Web 抢资源</td><td>「全在一台机」</td></tr><tr><td>V1 → V2</td><td>想要高可用</td><td>「单点 Web」</td></tr><tr><td>V2 → V3</td><td>DB 读 QPS 撑不住</td><td>「单 DB」</td></tr><tr><td>V3 → V4</td><td>团队 50+ / 业务多模块</td><td>「单库共享」</td></tr><tr><td>V4 → V5</td><td>单业务表撑不住</td><td>「单库单表」</td></tr><tr><td>V5 → V6</td><td>团队 200+ / 多业务线</td><td>「粗粒度服务」</td></tr><tr><td>V6 → V7</td><td>多语言 / 治理升级慢</td><td>「业务代码内治理」</td></tr><tr><td>V7 → V8</td><td>单机房物理上限</td><td>「单机房」</td></tr></tbody></table><blockquote><p>看着这张表逐行问「我现在卡在哪一行的瓶颈」——<strong>有清晰瓶颈才升级,没有就停在原地</strong>。最聪明的架构师是<strong>让公司在 V3 / V4 多停几年</strong>,因为那一段最划算。</p></blockquote><hr><h2 id="十一、反向警告-三个常见错误升级" tabindex="-1">十一、反向警告:三个常见错误升级 <a class="header-anchor" href="#十一、反向警告-三个常见错误升级" aria-label="Permalink to &quot;十一、反向警告:三个常见错误升级&quot;">​</a></h2><h3 id="_11-1-「我们要微服务」-v2-直接跳-v6" tabindex="-1">11.1 「我们要微服务」(V2 直接跳 V6) <a class="header-anchor" href="#_11-1-「我们要微服务」-v2-直接跳-v6" aria-label="Permalink to &quot;11.1 「我们要微服务」(V2 直接跳 V6)&quot;">​</a></h3><p>20 人团队,DAU 5 万,直接上 K8s + 30 个微服务。<strong>结果</strong>:60% 时间在搞基础设施,业务一年没进展。<strong>应该</strong>:V3 + 模块化单体撑 3 年。</p><h3 id="_11-2-「我们要分库分表」-v3-提前到-v5" tabindex="-1">11.2 「我们要分库分表」(V3 提前到 V5) <a class="header-anchor" href="#_11-2-「我们要分库分表」-v3-提前到-v5" aria-label="Permalink to &quot;11.2 「我们要分库分表」(V3 提前到 V5)&quot;">​</a></h3><p>数据 1 亿行,单库还能扛,被「分库分表潮流」忽悠分了 32 库。<strong>结果</strong>:跨库查询全部失效,后台报表写不出来。<strong>应该</strong>:先归档老数据 / 加索引 / 垂直拆分,顶不住再分。</p><h3 id="_11-3-「我们要-service-mesh」-v6-直接跳-v7" tabindex="-1">11.3 「我们要 Service Mesh」(V6 直接跳 V7) <a class="header-anchor" href="#_11-3-「我们要-service-mesh」-v6-直接跳-v7" aria-label="Permalink to &quot;11.3 「我们要 Service Mesh」(V6 直接跳 V7)&quot;">​</a></h3><p>Spring Cloud 用得好好的,听了一场布道大会决定上 Istio。<strong>结果</strong>:延迟涨 2ms,故障率上升,团队没人懂调优。<strong>应该</strong>:除非真的多语言 + 1000+ 服务,否则不要。</p><hr><h2 id="十二、踩坑提醒" tabindex="-1">十二、踩坑提醒 <a class="header-anchor" href="#十二、踩坑提醒" aria-label="Permalink to &quot;十二、踩坑提醒&quot;">​</a></h2><ol><li><strong>追潮流升级</strong>——架构升级要被瓶颈逼,不是看到大厂用就跟</li><li><strong>越级升级</strong>——V3 跳 V6 / V7,直接死</li><li><strong>不可逆决策提前做</strong>——分库分表、Cell 化都是 2 年内还不完的债</li><li><strong>以为新架构 = 新性能</strong>——微服务初期性能反而下降(网络多了一跳)</li><li><strong>忽略组织规模</strong>——架构演进本质是「应对组织复杂度」,不只是技术</li><li><strong>没有回滚计划</strong>——升级前必须有「打回原版」的应急方案</li><li><strong>看 PPT 不看真实运维</strong>——Netflix 的架构图很美,他们 SRE 团队 200 人你有几个?</li><li><strong>以为「单体落后」</strong>——Stack Overflow 单体到死,Shopify 单体到 IPO,<strong>单体 ≠ 落后</strong></li><li><strong>架构师当英雄</strong>——大改架构要全团队认可、分阶段、可灰度,<strong>没人能一口气改完</strong></li><li><strong>不算成本</strong>——每升一级,运维成本和人力都翻倍,<strong>老板不会无限投钱</strong></li></ol><hr><p>下一篇:<code>04-CAP-与一致性谱.md</code>,讲清楚 CAP 这个被讲烂但 90% 的人理解错的定理(C、A、P 不是任选其二),BASE 是怎么对 CAP 的工程化补丁,以及&quot;一致性&quot;其实是一个谱而不是 0/1——<strong>强一致 / 因果一致 / 单调一致 / 最终一致</strong> 各自适用什么场景。</p>`,116)])])}const u=n(e,[["render",t]]);export{h as __pageData,u as default};
